def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(2, a + 5):
                    temp = ((ratio - a) ** 6) / (a * b * 0.8 + 1)
                    priority += np.exp(-temp) * np.cos(ratio * b / (a + 2))
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.7
            if i % 2 == 0:
                for c in range(1, 5):
                    priority += np.cos(c * ratio * i) * np.log1p(c + ratio)
            else:
                for d in range(1, 6):
                    priority -= np.sin(d * ratio * i) * np.sqrt(d + ratio)
        elif 4 < ratio <= 7:
            for e in range(1, int(np.ceil(ratio)) + 5):
                for f in range(1, e + 4):
                    term = ((ratio - e) ** 4) * np.sin(ratio * f) / (f + 0.7)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            for g in range(1, 4):
                priority += (np.sin(g * ratio) + np.cos(g * i)) / (g + ratio)
        elif 2 <= ratio <= 4:
            s = 0
            for h in range(1, 15):
                s += ((ratio - 2) ** h) / (h * 2.0) * np.cos(h * ratio * 1.1)
            priority = (s * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority += penalty
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.sin(n * ratio * 2)
            priority = s + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 6):
                increment = np.cos(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.5)
                if m % 2 == 0:
                    priority += increment
                else:
                    priority -= increment
        elif 0.5 <= ratio < 1:
            s = 0
            for o in range(1, 18):
                s += ((1 - ratio) ** o) / (o * 3) * np.sin(o * item * 1.3)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for p in range(1, 7):
                priority += ((1 - ratio) ** p) * np.cos(p * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for q in range(1, 14):
                s += ((0.5 - ratio) ** q) / (q * 5) * np.cos(q * ratio * 3)
            priority = s
            if (i + int(item * 2.1)) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for r in range(1, 9):
                priority += ((0.5 - ratio) ** r) / (r * 7) * np.sin(item * r * 1.2)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for s_ in range(1, 16):
                s += ((0.2 - ratio) ** s_) / (s_ * 6) * np.cos(s_ * ratio * 2.5)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 1.5) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 6
            for t in range(1, 10):
                priority += ((0.2 - ratio) ** t) / (t * 8) * np.cos(item * t * 0.9)
        else:
            s = 0
            for u in range(1, 12):
                s += ((0.05 - ratio) ** u) / (u * 8) * np.sin(u * item * 1.0)
            priority = s + 3.5 / (bin_cap + 6)
            if int(item * 0.6) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 3) * 7
            for v in range(1, 9):
                priority += ((0.05 - ratio) ** v) / (v * 9) * np.cos(item * v * 0.7)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
            if i % 4 == 0:
                for w in range(1, 5):
                    priority += np.sin(w * ratio * i) * 0.4
                else:
                    for x in range(1, 5):
                        priority -= np.cos(x * ratio * i) * 0.4
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for y in range(1, 5):
            if (i + y) % 4 == 0:
                priority += np.sin(ratio * (i + y) * 1.1) * 0.5
            else:
                priority -= np.cos(ratio * (i + y) * 1.1) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
